e'] ?? null, null, $cw_config['qdrant_collection_name'] ?? null, null, $cw_config['chroma_collection_name'] ?? null, null ); if (!empty($vector_context)) { $system_instruction = "## Relevant information from knowledge base:\n" . trim($vector_context) . "\n##\n\n" . $system_instruction; } } } $user_prompt_template = AIPKit_Content_Writer_User_Prompt_Builder::build($cw_config); $rss_description = $cw_config['rss_description'] ?? ''; if (!empty($rss_description)) { $user_prompt_template = str_replace('{description}', trim($rss_description), $user_prompt_template); } $url_content = $cw_config['url_content_context'] ?? ''; if (!empty($url_content)) { $user_prompt_template = str_replace('{url_content}', trim($url_content), $user_prompt_template); } $source_url = $cw_config['source_url'] ?? ''; if (!empty($source_url)) { $user_prompt_template = str_replace('{source_url}', trim($source_url), $user_prompt_template); } $user_prompt = str_replace('{topic}', $final_title, $user_prompt_template); $user_prompt = str_replace('{keywords}', $final_keywords, $user_prompt); $user_prompt = str_replace('{description}', '', $user_prompt); $user_prompt = str_replace('{url_content}', '', $user_prompt); $user_prompt = str_replace('{source_url}', '', $user_prompt); return [ 'system_instruction' => $system_instruction, 'user_prompt' => $user_prompt, ]; } 